import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { fetchProducts } from "../services/api";
import logo from "../assets/logo.png";

const CATEGORIES = [
  "Todas",
  "Cepillos",
  "Pastas dentales",
  "Hilo dental",
  "Blanqueadores",
  "Enjuague bucal",
  "Otros",
];

const categoryColors = {
  Cepillos: "#dbeafe",
  "Pastas dentales": "#dcfce7",
  "Hilo dental": "#fef9c3",
  Blanqueadores: "#ede9fe",
  "Enjuague bucal": "#ffedd5",
  Otros: "#f1f5f9",
};

const categoryIcon = {
  Cepillos: "🪥",
  "Pastas dentales": "🧴",
  "Hilo dental": "🧵",
  Blanqueadores: "✨",
  "Enjuague bucal": "💧",
  Otros: "📦",
};

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: "#f0f9ff",
  },

  carousel: {
    width: "100%",
    height: "500px",
    position: "relative",
    overflow: "hidden",
  },

  overlay: {
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0,0.35)",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    color: "white",
    textAlign: "center",
    padding: "1.5rem",
  },

  title: {
    fontSize: "2.2rem",
    fontWeight: 600,
  },

  subtitle: {
    fontSize: "1.3rem",
    maxWidth: "650px",
  },

  container: {
    maxWidth: "1100px",
    margin: "0 auto",
    padding: "2rem",
  },

  filterRow: {
    display: "flex",
    flexWrap: "wrap",
    gap: "0.6rem",
    marginBottom: "2rem",
  },

  filterBtn: (active) => ({
    padding: "0.45rem 1.1rem",
    borderRadius: "20px",
    border: "1px solid #e2e8f0",
    backgroundColor: active ? "#32d5d5" : "white",
    color: active ? "white" : "#475569",
    fontWeight: 600,
    cursor: "pointer",
  }),

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))",
    gap: "1.5rem",
  },

  card: {
    backgroundColor: "white",
    borderRadius: "14px",
    boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
    overflow: "hidden",
    display: "flex",
    flexDirection: "column",
  },

  cardImg: {
    width: "100%",
    height: "180px",
    objectFit: "cover",
  },

  cardBody: {
    padding: "1.2rem",
    display: "flex",
    flexDirection: "column",
    gap: "0.5rem",
    flex: 1,
  },

  badge: (cat) => ({
    alignSelf: "flex-start",
    padding: "0.2rem 0.7rem",
    borderRadius: "20px",
    fontSize: "0.75rem",
    fontWeight: 600,
    backgroundColor: categoryColors[cat] || "#f1f5f9",
  }),

  name: {
    fontSize: "1rem",
    fontWeight: 700,
  },

  desc: {
    fontSize: "0.85rem",
    color: "#64748b",
    flex: 1,
  },

  priceRow: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },

  price: {
    fontSize: "1.2rem",
    fontWeight: 700,
    color: "#32d5d5",
  },

  stock: (n) => ({
    fontSize: "0.8rem",
    fontWeight: 600,
    color: n === 0 ? "#ef4444" : "#16a34a",
  }),

  addBtn: (inCart, outOfStock) => ({
    width: "100%",
    padding: "0.75rem",
    marginTop: "0.8rem",
    borderRadius: "10px",
    border: "none",
    fontWeight: 700,
    cursor: outOfStock ? "not-allowed" : "pointer",
    backgroundColor: outOfStock ? "#e2e8f0" : inCart ? "#dcfce7" : "#32d5d5",
    color: outOfStock ? "#94a3b8" : inCart ? "#16a34a" : "white",
  }),

  cartBtn: {
    position: "absolute",
    top: 20,
    right: 20,
    zIndex: 999,
    padding: "0.7rem 1.3rem",
    background: "white",
    borderRadius: "30px",
    fontWeight: 700,
    cursor: "pointer",
  },
};

export default function Store() {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [activeCategory, setActiveCategory] = useState("Todas");
  const [cart, setCart] = useState([]);
  const [currentImage, setCurrentImage] = useState(0);

  const navigate = useNavigate();

  const slides = [
    {
      image:
        "https://gacetamedica.com/wp-content/uploads/2023/06/GettyImages-1409041204.jpg",
      title: "Tu salud importa",
      subtitle: "Jornadas de atención gratuita",
    },
    {
      image:
        "https://cdn.firespring.com/images/80f7ee1f-f74d-4840-ad81-4eb596834a04.jpg",
      title: "Tu sonrisa es digna",
      subtitle: "Atención personalizada",
    },
    {
      image:
        "https://sdk-dentalcollege.edu.in/sdk-cms/images/bannerimages/1524651961_large.jpg",
      title: "Tu derecho es nuestra accesibilidad",
      subtitle: "Jornadas barriales gratuitas",
    },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImage((p) => (p + 1) % slides.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const isLoggedIn = Boolean(localStorage.getItem("token"));

  useEffect(() => {
    fetchProducts().then((res) => {
      setProducts(res.data || []);
      setFiltered(res.data || []);
    });
  }, []);

  const handleFilter = (cat) => {
    setActiveCategory(cat);
    setFiltered(
      cat === "Todas" ? products : products.filter((p) => p.category === cat),
    );
  };

  const handleAddToCart = (p) => {
    if (!isLoggedIn) return navigate("/login");

    setCart((prev) => {
      const ex = prev.find((i) => i.id === p.id);
      if (ex) {
        return prev.map((i) => (i.id === p.id ? { ...i, qty: i.qty + 1 } : i));
      }
      return [...prev, { ...p, qty: 1 }];
    });
  };

  const cartCount = cart.reduce((s, i) => s + i.qty, 0);
  const cartTotal = cart.reduce((s, i) => s + i.price * i.qty, 0);

  return (
    <div style={styles.page}>
      <div style={styles.carousel}>
        <div
          style={{
            width: "100%",
            height: "100%",
            backgroundImage: `url(${slides[currentImage].image})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            position: "relative",
          }}
        >
          {cartCount > 0 && (
            <div
              style={styles.cartBtn}
              onClick={() => navigate("/checkout", { state: { cart } })}
            >
              🛒 {cartCount} | ${cartTotal.toFixed(2)}
            </div>
          )}

          <div style={styles.overlay}>
            <img src={logo} style={{ width: "300px" }} />
            <h1 style={styles.title}>{slides[currentImage].title}</h1>
            <p style={styles.subtitle}>{slides[currentImage].subtitle}</p>
          </div>
        </div>
      </div>

      <div style={styles.container}>
        <div style={styles.filterRow}>
          {CATEGORIES.map((c) => (
            <button
              key={c}
              style={styles.filterBtn(activeCategory === c)}
              onClick={() => handleFilter(c)}
            >
              {c}
            </button>
          ))}
        </div>

        <div style={styles.grid}>
          {filtered.map((p) => {
            const out = p.stock === 0;
            const inCart = cart.some((i) => i.id === p.id);

            return (
              <div key={p.id} style={styles.card}>
                <img src={p.imageUrl} style={styles.cardImg} />

                <div style={styles.cardBody}>
                  <span style={styles.badge(p.category)}>{p.category}</span>

                  <div style={styles.name}>{p.name}</div>
                  <div style={styles.desc}>{p.description}</div>

                  <div style={styles.priceRow}>
                    <div style={styles.price}>${p.price}</div>
                    <div style={styles.stock(p.stock)}>
                      {out ? "Sin stock" : `${p.stock} disponibles`}
                    </div>
                  </div>

                  <button
                    style={styles.addBtn(inCart, out)}
                    onClick={() => handleAddToCart(p)}
                  >
                    Agregar al carrito
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
